// ===== HELPER FUNCTIONS =====

function decode(str) {
  return str.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ').replace(/&#(\d+);/g, (m, c) => String.fromCharCode(c));
}

// Extract name from Gmail's {value:[{address,name}]} format
function getName(field) {
  if (!field) return '';
  if (typeof field === 'string') {
    const m = field.match(/^"?([^"<]+)"?\s*</);
    return m ? m[1].trim() : field.replace(/"/g, '').trim();
  }
  if (typeof field === 'object' && !Array.isArray(field)) {
    if (field.value && Array.isArray(field.value)) {
      return field.value.map(v => (v.name || v.address || '').replace(/"/g, '').trim()).join(', ');
    }
    return (field.name || field.address || '').replace(/"/g, '').trim();
  }
  if (Array.isArray(field)) return field.map(f => getName(f)).join(', ');
  return String(field);
}

// Extract email from Gmail's {value:[{address,name}]} format
function getEmail(field) {
  if (!field) return '';
  if (typeof field === 'string') {
    const m = field.match(/<([^>]+)>/);
    return m ? m[1] : field;
  }
  if (typeof field === 'object' && !Array.isArray(field)) {
    if (field.value && Array.isArray(field.value) && field.value[0]) {
      return field.value[0].address || field.value[0].email || '';
    }
    return field.email || field.address || '';
  }
  return String(field);
}

// Format HTML to clean plain text following these rules:
// - Remove ALL HTML tags entirely
// - Convert line breaks and paragraph tags into natural line breaks
// - Do NOT use any headings — plain text blocks only
// - Preserve bullet points and numbered lists, max 2 levels deep
// - Keep all original text exactly as written — no summarizing
// - Remove inline styles, scripts, metadata
function formatHtml(html) {
  if (!html) return '';

  // Remove style, script, comments
  html = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
  html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
  html = html.replace(/<!--[\s\S]*?-->/g, '');

  // Convert links: preserve as text (url)
  html = html.replace(/<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi, (m, url, text) => {
    text = text.replace(/<[^>]+>/g, '').trim();
    if (!text || text === url) return url;
    return text + ' (' + url + ')';
  });

  // Convert block elements to line breaks
  html = html.replace(/<br\s*\/?>/gi, '\n');
  html = html.replace(/<\/(p|div|blockquote)>/gi, '\n\n');
  html = html.replace(/<p[^>]*>/gi, '');
  html = html.replace(/<div[^>]*>/gi, '');
  html = html.replace(/<blockquote[^>]*>/gi, '');

  // Tables: rows become lines, cells become spaces
  html = html.replace(/<\/(tr)>/gi, '\n');
  html = html.replace(/<\/(td|th)>/gi, ' ');

  // Horizontal rules
  html = html.replace(/<hr[^>]*>/gi, '\n---\n');

  // Headings: convert to plain text (no heading formatting)
  html = html.replace(/<h[1-6][^>]*>/gi, '\n');
  html = html.replace(/<\/h[1-6]>/gi, '\n\n');

  // Lists: preserve bullet points, flatten to max 2 levels
  html = html.replace(/<\/li>/gi, '\n');
  // Nested lists (3+ deep) — flatten
  html = html.replace(/<(ul|ol)[^>]*>/gi, '');
  html = html.replace(/<\/(ul|ol)>/gi, '');
  html = html.replace(/<li[^>]*>/gi, '\u2022 ');

  // Strip ALL remaining HTML tags
  html = html.replace(/<[^>]+>/g, '');

  // Decode HTML entities
  html = decode(html);

  // Clean up whitespace
  html = html.replace(/[ \t]+/g, ' ');
  html = html.replace(/\n[ \t]+/g, '\n');
  html = html.replace(/[ \t]+\n/g, '\n');
  html = html.replace(/\n{3,}/g, '\n\n');

  return html.trim();
}

