for (const item of $input.all()) {
  const json = item.json;

  // Extract fields
  const rawFrom = json.from || json.From;
  const rawTo = json.to || json.To;
  const fromName = getName(rawFrom);
  const toName = getName(rawTo);
  const fromEmail = getEmail(rawFrom).toLowerCase();
  const subject = json.subject || json.Subject || '';
  const date = json.date || json.Date || '';
  const messageUrl = json.messageUrl || ('https://mail.google.com/mail/u/0/#inbox/' + (json.id || ''));

  // Contact name: if Tom sent it, use recipient; otherwise use sender
  const isTom = fromEmail.includes('tom.dewire@gmail.com');
  item.json.contactName = isTom ? toName : fromName;

  // Format email body from HTML
  const bodyHtml = json.textHtml || json.html || '';
  const bodyFormatted = formatHtml(bodyHtml) || json.textPlain || json.text || json.snippet || '';

  // Detect attachments
  const binaryKeys = Object.keys(item.binary || {}).filter(k => k.startsWith('attachment_'));
  const attachmentNames = binaryKeys.map(k => (item.binary[k].fileName || k));

  // Build full "Name <email>" for From/To display
  const fromDisplay = fromName && fromEmail ? fromName + ' <' + getEmail(rawFrom) + '>' : fromName || getEmail(rawFrom);
  const toDisplay = (() => {
    if (!rawTo) return '';
    if (typeof rawTo === 'object' && !Array.isArray(rawTo) && rawTo.value && Array.isArray(rawTo.value)) {
      return rawTo.value.map(v => {
        const n = (v.name || '').replace(/"/g, '').trim();
        const e = (v.address || v.email || '').trim();
        if (n && e) return n + ' <' + e + '>';
        return e || n || '';
      }).filter(s => s).join(', ');
    }
    const tn = toName;
    const te = getEmail(rawTo);
    return tn && te ? tn + ' <' + te + '>' : tn || te;
  })();

  let formatted = 'From: ' + fromDisplay;
  formatted += '\nTo: ' + toDisplay;
  formatted += '\nDate: ' + date;
  formatted += '\nSubject: ' + subject;
  formatted += '\nEmail URL: ' + messageUrl;
  formatted += '\n\n---\n\n';
  formatted += bodyFormatted;
  formatted += '\n\n---\nAttachments:\n';
  if (attachmentNames.length > 0) {
    formatted += attachmentNames.map(n => n).join('\n');
  } else {
    formatted += 'No attachments.';
  }

  // Store results
  item.json.formattedEmail = formatted;
  item.json.subject = subject;
  item.json.date = date;
  item.json.from = fromName;
  item.json.to = toName;
  item.json.messageUrl = messageUrl;
  item.json.hasAttachments = binaryKeys.length > 0;
  item.json.attachmentNames = attachmentNames;
  item.json.attachmentText = '';
