  const urlMatch = pageTitle.match(/https:\/\/mail\.google\.com\/[^\s]+/);
  const currentMessageUrl = urlMatch ? urlMatch[0] : '';

  let matchingEmail = null;
  if (currentMessageUrl) {
    matchingEmail = allExtracted.find(item => item.json.messageUrl === currentMessageUrl);
  }
  if (!matchingEmail) matchingEmail = allExtracted[0];

  const formattedEmail = (matchingEmail && matchingEmail.json && matchingEmail.json.formattedEmail) || '';

  let attachmentLinks = null;
  if (currentMessageUrl) {
    const matchingAtt = allAttachments.find(item => item.json.messageUrl === currentMessageUrl);
    attachmentLinks = (matchingAtt && matchingAtt.json && matchingAtt.json.attachmentLinks) || null;
  }

  // Strip attachment section from main content
  const attachRegex = /\n\n---\nAttachments:\n[\s\S]*$/;
  const mainContent = formattedEmail.replace(attachRegex, '');

  // Split main content into 2000-char chunks at newlines
  const chunks = [];
  let remaining = mainContent;
  while (remaining.length > 0) {
    let chunk = remaining.substring(0, 2000);
    if (remaining.length > 2000) {
      const lastNewline = chunk.lastIndexOf('\n');
      if (lastNewline > 500) chunk = remaining.substring(0, lastNewline + 1);
    }
    chunks.push(chunk);
    remaining = remaining.substring(chunk.length);
  }

  const children = chunks.map(text => ({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: text } }]
    }
  }));

  // Attachment section as Notion link blocks
  children.push({
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: '---\nAttachments:' } }]
    }
  });

  if (attachmentLinks && attachmentLinks.length > 0) {
    for (const link of attachmentLinks) {
      children.push({
        object: 'block',
        type: 'paragraph',
        paragraph: {
          rich_text: [
            { type: 'text', text: { content: '• ' } },
            { type: 'text', text: { content: link.name, link: { url: link.url } } }
          ]
        }
      });
    }
  } else {
    children.push({
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [{ type: 'text', text: { content: 'No attachments.' } }]
      }
    });
  }

  // Notion limits children per PATCH to 100; batch if needed
  for (let b = 0; b < children.length; b += 100) {
    results.push({
      json: { pageId, children: children.slice(b, b + 100) }
    });
  }
}

return results;

